mapper.select:
SELECT MEMBER_ID AS memberId, NICKNAME AS memberNickname, EMAIL AS memberEmail, PHONE AS memberPhone, ROLE AS memberRole, EMAIL_VERIFIED AS emailVerified
FROM APP_MEMBER
WHERE MEMBER_ID = #{memberId}

